import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../providers/delivery_provider.dart'; class DeliveryScreen extends ConsumerStatefulWidget { const DeliveryScreen({super.key}); @override ConsumerState<DeliveryScreen> createState() => _DeliveryScreenState(); } class _DeliveryScreenState extends ConsumerState<DeliveryScreen> { @override void initState() { super.initState(); WidgetsBinding.instance.addPostFrameCallback((_)=>ref.read(deliveryProvider.notifier).load()); } @override Widget build(BuildContext context) { final state = ref.watch(deliveryProvider); return Scaffold(appBar: AppBar(title: const Text('طلبات التوصيل')), body: state.loading? const Center(child: CircularProgressIndicator()) : ListView.builder(itemCount: state.orders.length, itemBuilder: (c,i){ final o = state.orders[i]; return Card(margin: const EdgeInsets.all(8), child: ListTile(title: Text(o.customerName), subtitle: Text(o.customerPhone), trailing: ElevatedButton(onPressed: ()=>ref.read(deliveryProvider.notifier).updateStatus(o.id, 'delivered'), child: const Text('تسليم')))); })); } }
